class Solution {
    public int[] validSequence(String word1, String word2) {
        int m = word1.length(), n = word2.length();
        int[][] dp = new int[m + 1][n + 1];
        for (int i = 0; i <= m; i++) {
            for (int j = 0; j <= n; j++) {
                dp[i][j] = -1;
            }
        }
        dp[0][0] = 0;
        for (int i = 1; i <= m; i++) {
            for (int j = 0; j <= n; j++) {
                if (dp[i - 1][j] != -1) {
                    dp[i][j] = Math.max(dp[i][j], dp[i - 1][j]);
                }
                if (j < n && word1.charAt(i - 1) == word2.charAt(j)) {
                    dp[i][j + 1] = Math.max(dp[i][j + 1], dp[i - 1][j] + 1);
                }
            }
        }
        if (dp[m][n] != n) {
            return new int[0];
        }
        int[] res = new int[n];
        int idx = n - 1;
        for (int i = m; i > 0; i--) {
            if (dp[i][idx + 1] == dp[i - 1][idx]) {
                res[idx] = i - 1;
                idx--;
            }
        }
        return res;
    }
}
